#!/bin/bash
echo "Installing Stripe files..."
echo '' | base64 -d > /var/www/francos-pet/server/stripe.ts
echo "stripe.ts: $(wc -l < /var/www/francos-pet/server/stripe.ts) lines"
echo '' | base64 -d > /var/www/francos-pet/client/src/components/StripeCheckout.tsx
echo "StripeCheckout.tsx: $(wc -l < /var/www/francos-pet/client/src/components/StripeCheckout.tsx) lines"
sed -i 's|import CardCheckout from "@/components/CardCheckout";|import StripeCheckout from "@/components/StripeCheckout";|' /var/www/francos-pet/client/src/pages/CheckoutPage.tsx
grep -n "StripeCheckout\|CardCheckout" /var/www/francos-pet/client/src/pages/CheckoutPage.tsx | head -5
if ! grep -q "registerStripeRoutes" /var/www/francos-pet/server/routes.ts; then
  sed -i 's|from "./renewals";|from "./renewals";
import { verifyPaymentIntent, chargeCustomer, deleteStripeCustomer, registerStripeRoutes } from "./stripe";|' /var/www/francos-pet/server/routes.ts
fi
if ! grep -q '"stripe"' /var/www/francos-pet/script/build.ts; then
  sed -i 's|"zod-validation-error",|"zod-validation-error",\n  "stripe",|' /var/www/francos-pet/script/build.ts
fi
echo "Done! Now run: npm run build && pm2 restart francos-pet --update-env"
